        if (!metadata.title && metadata.ogTags['og:title']) {
            metadata.title = metadata.ogTags['og:title'];
        }
        if (!metadata.description && metadata.ogTags['og:description']) {
            metadata.description = metadata.ogTags['og:description'];
        }

        // Remove the ogTags object if no Open Graph tags were found to keep the response clean
        if (Object.keys(metadata.ogTags).length === 0) {
            delete metadata.ogTags;
        }

